mapper.select:
select nc_page.id, nc_page.name as ncName, nc_page.title, nc_page.band_number as bandNumber,
nc_page.nc_path as ncPath, nc_page.img_path as imgPath,
nc_page.satellite_type as satelliteType, nc_page.resolution, nc_page.img_type as imgType,
nc_page.process_type as processType, nc_page.start_time as startTime, nc_page.end_time as endTime,
ST_AsGeoJSON(nc_page.geometry) as ncGeometry, china.name, china.gb,
ST_AsGeoJSON(china.geometry) as geometry
from (
    select nc.id, nc.name, nc.title, nc.band_number, nc.nc_path, nc.img_path,
    nc.satellite_type, nc.resolution, nc.img_type, nc.process_type,
    nc.start_time, nc.end_time, nc.geometry
    from nc
     1=1
        and nc.name like '%' || #{name} || '%'
        and nc.title like '%' || #{title} || '%'
        and nc.band_number = #{band_number}

            and exists (
                select 1
                from china c_filter
                where ST_Contains(nc.geometry, c_filter.geometry)
                  and c_filter.name like '%' || #{region_name} || '%'
            )

        and nc.satellite_type = #{satellite_type}
        and nc.resolution = #{resolution}
        and nc.img_type = #{img_type}
        and nc.process_type = #{process_type}
        and nc.start_time >= #{begin_date}
        and nc.end_time <= #{end_date}

    order by nc.id
    limit #{page_size} offset #{offset}
) nc_page
left join lateral (
    select c.name, c.gb, c.geometry
    from china c
    where ST_Contains(nc_page.geometry, c.geometry)
    order by c.name
    limit 1
) china on true
order by nc_page.id

select count(*)
from nc
 1=1
    and nc.name like '%' || #{name} || '%'
    and nc.title like '%' || #{title} || '%'
    and nc.band_number = #{band_number}

        and exists (
            select 1
            from china c_filter
            where ST_Contains(nc.geometry, c_filter.geometry)
              and c_filter.name like '%' || #{region_name} || '%'
        )

    and nc.satellite_type = #{satellite_type}
    and nc.resolution = #{resolution}
    and nc.img_type = #{img_type}
    and nc.process_type = #{process_type}
    and nc.start_time >= #{begin_date}
    and nc.end_time <= #{end_date}
